USE suzhou_bank_report;
CREATE TABLE IF NOT EXISTS customer (id BIGINT PRIMARY KEY AUTO_INCREMENT, company_name VARCHAR(200) NOT NULL, credit_code VARCHAR(50), legal_person VARCHAR(50), actual_controller VARCHAR(50), registered_capital VARCHAR(50), paid_capital VARCHAR(50), establish_date DATE, industry VARCHAR(100), biz_scope TEXT, register_address VARCHAR(300), holding_type VARCHAR(30), shareholder VARCHAR(500), group_name VARCHAR(200), customer_type VARCHAR(30), first_loan_date DATE, last_approval_date DATE, main_bank VARCHAR(200), settlement_bank VARCHAR(200), status VARCHAR(20) DEFAULT 'ACTIVE', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_company_name (company_name));
CREATE TABLE IF NOT EXISTS collector_config (id BIGINT PRIMARY KEY AUTO_INCREMENT, config_name VARCHAR(100) NOT NULL, collector_type VARCHAR(30) NOT NULL, config_json TEXT NOT NULL, cron_expression VARCHAR(50), enabled TINYINT(1) DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_type (collector_type));
CREATE TABLE IF NOT EXISTS parser_config (id BIGINT PRIMARY KEY AUTO_INCREMENT, collector_id BIGINT NOT NULL, parser_type VARCHAR(30) NOT NULL, config_json TEXT NOT NULL, domain VARCHAR(30) NOT NULL, sort_order INT DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_collector (collector_id));
CREATE TABLE IF NOT EXISTS raw_data_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, collector_id BIGINT, raw_content MEDIUMTEXT, content_type VARCHAR(50), file_path VARCHAR(500), collect_time DATETIME NOT NULL, customer_id BIGINT, success TINYINT(1) DEFAULT 1, error_msg TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX idx_customer (customer_id), INDEX idx_collect_time (collect_time));
CREATE TABLE IF NOT EXISTS indicator_data (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, indicator_key VARCHAR(100) NOT NULL, indicator_name VARCHAR(200) NOT NULL, current_value VARCHAR(100), previous_value VARCHAR(100), change_desc VARCHAR(100), data_unit VARCHAR(50), domain VARCHAR(30) NOT NULL, period VARCHAR(30), sort_order INT DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX idx_customer_domain (customer_id, domain), INDEX idx_customer_key (customer_id, indicator_key));
CREATE TABLE IF NOT EXISTS text_data (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, text_type VARCHAR(50) NOT NULL, domain VARCHAR(30) NOT NULL, title VARCHAR(300), content MEDIUMTEXT NOT NULL, period VARCHAR(30), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX idx_customer_domain (customer_id, domain));
CREATE TABLE IF NOT EXISTS credit_record (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, contract_no VARCHAR(100), loan_type VARCHAR(30), currency VARCHAR(10), loan_amount VARCHAR(50), loan_balance VARCHAR(50), start_date DATE, end_date DATE, loan_purpose VARCHAR(200), guarantee_type VARCHAR(50), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX idx_customer (customer_id));
CREATE TABLE IF NOT EXISTS knowledge_rule (id BIGINT PRIMARY KEY AUTO_INCREMENT, rule_code VARCHAR(50) NOT NULL, rule_name VARCHAR(200) NOT NULL, rule_type VARCHAR(30) NOT NULL, description TEXT, enabled TINYINT(1) DEFAULT 1, sort_order INT DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uk_code (rule_code));
CREATE TABLE IF NOT EXISTS rule_condition (id BIGINT PRIMARY KEY AUTO_INCREMENT, rule_id BIGINT NOT NULL, indicator_key VARCHAR(100) NOT NULL, operator VARCHAR(20) NOT NULL, threshold VARCHAR(50), logic_order INT DEFAULT 1, logic_connector VARCHAR(5) DEFAULT 'AND', INDEX idx_rule (rule_id));
CREATE TABLE IF NOT EXISTS rule_tag (id BIGINT PRIMARY KEY AUTO_INCREMENT, rule_id BIGINT NOT NULL, tag_type VARCHAR(30) NOT NULL, tag_value VARCHAR(100) NOT NULL, INDEX idx_type_value (tag_type, tag_value), INDEX idx_rule (rule_id));
CREATE TABLE IF NOT EXISTS rule_scenario (id BIGINT PRIMARY KEY AUTO_INCREMENT, scenario_code VARCHAR(50) NOT NULL, scenario_name VARCHAR(100) NOT NULL, description TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uk_code (scenario_code));
CREATE TABLE IF NOT EXISTS know_kit_task (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, scenario_tags VARCHAR(500), request_json MEDIUMTEXT, response_json MEDIUMTEXT, status VARCHAR(20) DEFAULT 'PENDING', error_msg TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, completed_at DATETIME, INDEX idx_customer (customer_id), INDEX idx_status (status));
CREATE TABLE IF NOT EXISTS report (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, report_title VARCHAR(300) NOT NULL, report_type VARCHAR(50) NOT NULL, status VARCHAR(20) DEFAULT 'DRAFT', know_kit_task_id BIGINT, content_html MEDIUMTEXT, data_snapshot MEDIUMTEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_customer (customer_id), INDEX idx_type (report_type));
